{
  "name": "SnowTest - ServiceNow Integration Dashboard",
  "description": "A modern, pastel-themed integration testing dashboard optimized for ServiceNow REST APIs. Features inbound request testing, simulated outbound webhook listening, and request history analytics."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type HttpMethod = 'GET' | 'POST' | 'PUT' | 'DELETE' | 'PATCH';

export interface KeyValue {
  id: string;
  key: string;
  value: string;
  active: boolean;
}

export interface RequestHistoryItem {
  id: string;
  timestamp: number;
  method: HttpMethod;
  url: string;
  status: number;
  duration: number;
  success: boolean;
  requestBody?: string;
  responseBody?: string;
}

export interface EnvironmentSettings {
  instanceUrl: string;
  username: string;
  password?: string; // Optional for security (often not stored in full plain text in real apps)
  token?: string;
  useMockMode: boolean;
  defaultHeaders: KeyValue[];
}

export interface WebhookEvent {
  id: string;
  timestamp: number;
  method: HttpMethod;
  headers: Record<string, string>;
  body: any;
  source: string;
}

export enum AppTab {
  INBOUND = 'inbound',
  OUTBOUND = 'outbound',
  HISTORY = 'history',
  SETTINGS = 'settings',
  DASHBOARD = 'dashboard'
}

import { KeyValue } from './types';

export const DEFAULT_HEADERS: KeyValue[] = [
  { id: '1', key: 'Content-Type', value: 'application/json', active: true },
  { id: '2', key: 'Accept', value: 'application/json', active: true },
];

export const MOCK_WEBHOOK_PAYLOADS = [
  {
    short_description: "Email server is down",
    priority: "1",
    caller_id: "admin",
    category: "Network",
    state: "New"
  },
  {
    short_description: "Laptop request for new hire",
    priority: "3",
    caller_id: "abel.tuter",
    category: "Hardware",
    state: "In Progress"
  },
  {
    event: "record.updated",
    table: "incident",
    sys_id: "sys_id_placeholder_123",
    changes: ["state", "assigned_to"]
  }
];

export const STATUS_COLORS = {
  success: 'text-emerald-500 bg-emerald-50 border-emerald-200',
  error: 'text-rose-500 bg-rose-50 border-rose-200',
  warning: 'text-amber-500 bg-amber-50 border-amber-200',
  neutral: 'text-slate-500 bg-slate-50 border-slate-200',
};

import { EnvironmentSettings, RequestHistoryItem, KeyValue } from '../types';
import { DEFAULT_HEADERS } from '../constants';

const KEYS = {
  SETTINGS: 'snowtest_settings',
  HISTORY: 'snowtest_history',
  THEME: 'snowtest_theme'
};

export const getSettings = (): EnvironmentSettings => {
  const saved = localStorage.getItem(KEYS.SETTINGS);
  if (saved) {
    return JSON.parse(saved);
  }
  return {
    instanceUrl: 'https://dev00000.service-now.com',
    username: 'admin',
    useMockMode: true,
    defaultHeaders: DEFAULT_HEADERS
  };
};

export const saveSettings = (settings: EnvironmentSettings) => {
  localStorage.setItem(KEYS.SETTINGS, JSON.stringify(settings));
};

export const getHistory = (): RequestHistoryItem[] => {
  const saved = localStorage.getItem(KEYS.HISTORY);
  return saved ? JSON.parse(saved) : [];
};

export const saveHistoryItem = (item: RequestHistoryItem) => {
  const history = getHistory();
  const newHistory = [item, ...history].slice(0, 50); // Keep last 50
  localStorage.setItem(KEYS.HISTORY, JSON.stringify(newHistory));
};

export const clearHistory = () => {
  localStorage.removeItem(KEYS.HISTORY);
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost' | 'outline';
  size?: 'sm' | 'md' | 'lg';
  isLoading?: boolean;
  icon?: React.ReactNode;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  isLoading, 
  icon,
  className = '',
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center font-medium transition-all focus:outline-none focus:ring-2 focus:ring-offset-1 disabled:opacity-50 disabled:cursor-not-allowed rounded-xl";

  const variants = {
    primary: "bg-primary-600 hover:bg-primary-700 text-white shadow-lg shadow-primary-200 focus:ring-primary-500",
    secondary: "bg-white hover:bg-slate-50 text-slate-700 border border-slate-200 shadow-sm focus:ring-slate-200",
    danger: "bg-rose-500 hover:bg-rose-600 text-white shadow-lg shadow-rose-200 focus:ring-rose-500",
    ghost: "bg-transparent hover:bg-slate-100 text-slate-600",
    outline: "bg-transparent border border-primary-600 text-primary-600 hover:bg-primary-50"
  };

  const sizes = {
    sm: "text-xs px-3 py-1.5 gap-1.5",
    md: "text-sm px-4 py-2 gap-2",
    lg: "text-base px-6 py-3 gap-2.5"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
      disabled={isLoading || props.disabled}
      {...props}
    >
      {isLoading && (
        <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      )}
      {!isLoading && icon}
      {children}
    </button>
  );
};

import React, { useState, useEffect } from 'react';
import { Send, Plus, Trash2, Code, Play, AlertCircle, CheckCircle, Copy, Terminal } from 'lucide-react';
import { Button } from './ui/Button';
import { EnvironmentSettings, HttpMethod, KeyValue, RequestHistoryItem } from '../types';
import { saveHistoryItem } from '../services/storageService';
import Prism from 'prismjs';
import 'prismjs/themes/prism.css';

interface InboundTesterProps {
  settings: EnvironmentSettings;
}

export const InboundTester: React.FC<InboundTesterProps> = ({ settings }) => {
  const [method, setMethod] = useState<HttpMethod>('GET');
  const [endpoint, setEndpoint] = useState('/api/now/table/incident');
  const [headers, setHeaders] = useState<KeyValue[]>(settings.defaultHeaders);
  const [body, setBody] = useState('{\n  "short_description": "Test Incident from SnowTest",\n  "urgency": "2"\n}');
  const [response, setResponse] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState<'params' | 'auth' | 'headers' | 'body'>('params');

  // Prism highlight effect
  useEffect(() => {
    if (response) {
      Prism.highlightAll();
    }
  }, [response]);

  const handleAddHeader = () => {
    setHeaders([...headers, { id: Date.now().toString(), key: '', value: '', active: true }]);
  };

  const handleRemoveHeader = (id: string) => {
    setHeaders(headers.filter(h => h.id !== id));
  };

  const handleHeaderChange = (id: string, field: 'key' | 'value', val: string) => {
    setHeaders(headers.map(h => h.id === id ? { ...h, [field]: val } : h));
  };

  const generateCurl = () => {
    const headerStr = headers
      .filter(h => h.active && h.key)
      .map(h => `-H "${h.key}: ${h.value}"`)
      .join(' ');

    const url = endpoint.startsWith('http') ? endpoint : `${settings.instanceUrl}${endpoint}`;
    const auth = settings.username ? `-u "${settings.username}:******"` : '';
    const data = method !== 'GET' && method !== 'DELETE' ? `-d '${body.replace(/\n/g, '')}'` : '';

    return `curl -X ${method} "${url}" ${headerStr} ${auth} ${data}`;
  };

  const handleSend = async () => {
    setLoading(true);
    setResponse(null);
    const startTime = Date.now();

    const url = endpoint.startsWith('http') ? endpoint : `${settings.instanceUrl}${endpoint}`;

    try {
      const activeHeaders = headers.reduce((acc, h) => {
        if (h.active && h.key) acc[h.key] = h.value;
        return acc;
      }, {} as Record<string, string>);

      // Add Auth
      if (settings.username && settings.password) {
        activeHeaders['Authorization'] = 'Basic ' + btoa(`${settings.username}:${settings.password}`);
      }

      let fetchResponse;

      if (settings.useMockMode) {
        // Mock delay
        await new Promise(r => setTimeout(r, 800));
        fetchResponse = {
          status: 201,
          ok: true,
          json: async () => ({
            result: {
              sys_id: "mock_sys_id_" + Date.now(),
              number: "INC0010002",
              short_description: JSON.parse(body).short_description || "Mock Incident",
              state: "New",
              opened_at: new Date().toISOString()
            }
          })
        };
      } else {
         fetchResponse = await fetch(url, {
          method,
          headers: activeHeaders,
          body: (method !== 'GET' && method !== 'HEAD') ? body : undefined
        });
      }

      const responseData = await fetchResponse.json();
      const endTime = Date.now();
      const duration = endTime - startTime;

      const historyItem: RequestHistoryItem = {
        id: Date.now().toString(),
        timestamp: startTime,
        method,
        url,
        status: fetchResponse.status || 200,
        duration,
        success: fetchResponse.ok || (fetchResponse.status >= 200 && fetchResponse.status < 300),
        requestBody: body,
        responseBody: JSON.stringify(responseData)
      };

      saveHistoryItem(historyItem);
      setResponse({
        status: fetchResponse.status || 200,
        statusText: fetchResponse.ok ? 'OK' : 'Error',
        data: responseData,
        time: duration,
        size: JSON.stringify(responseData).length
      });

    } catch (error: any) {
      setResponse({
        error: true,
        message: error.message,
        status: 0,
        statusText: 'Network Error'
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full gap-6">
      {/* Request Composer Card */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-4 border-b border-slate-100 flex items-center gap-3">
          <select 
            value={method}
            onChange={(e) => setMethod(e.target.value as HttpMethod)}
            className="bg-slate-50 border border-slate-200 text-slate-700 text-sm rounded-lg focus:ring-primary-500 focus:border-primary-500 block p-2.5 font-mono font-bold"
          >
            {['GET', 'POST', 'PUT', 'PATCH', 'DELETE'].map(m => (
              <option key={m} value={m}>{m}</option>
            ))}
          </select>
          <div className="flex-1 relative">
             <span className="absolute left-3 top-2.5 text-slate-400 text-sm font-mono select-none">
                {settings.instanceUrl ? '' : 'https://'}
             </span>
             <input
              type="text"
              value={endpoint}
              onChange={(e) => setEndpoint(e.target.value)}
              placeholder="Enter endpoint (e.g. /api/now/table/incident)"
              className="bg-slate-50 border border-slate-200 text-slate-700 text-sm rounded-lg focus:ring-primary-500 focus:border-primary-500 block w-full p-2.5 font-mono pl-3"
            />
          </div>
          <Button onClick={handleSend} isLoading={loading} icon={<Send size={16} />}>
            Send
          </Button>
        </div>

        {/* Tabs */}
        <div className="flex border-b border-slate-100 bg-slate-50/50">
          {[
            { id: 'params', label: 'Params' },
            { id: 'auth', label: 'Auth' },
            { id: 'headers', label: `Headers (${headers.length})` },
            { id: 'body', label: 'Body' },
          ].map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`px-4 py-3 text-sm font-medium transition-colors ${
                activeTab === tab.id 
                  ? 'text-primary-600 border-b-2 border-primary-600 bg-white' 
                  : 'text-slate-500 hover:text-slate-700 hover:bg-slate-100'
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>

        {/* Tab Content */}
        <div className="p-4 min-h-[200px]">
          {activeTab === 'headers' && (
            <div className="space-y-2">
              {headers.map((h) => (
                <div key={h.id} className="flex gap-2">
                  <input
                    type="checkbox"
                    checked={h.active}
                    onChange={(e) => {
                      const newHeaders = headers.map(header => header.id === h.id ? {...header, active: e.target.checked} : header);
                      setHeaders(newHeaders);
                    }}
                    className="mt-2.5 rounded border-slate-300 text-primary-600 focus:ring-primary-500"
                  />
                  <input
                    placeholder="Key"
                    value={h.key}
                    onChange={(e) => handleHeaderChange(h.id, 'key', e.target.value)}
                    className="flex-1 text-sm border border-slate-200 rounded-lg px-3 py-2 font-mono focus:ring-primary-500 focus:border-primary-500"
                  />
                  <input
                    placeholder="Value"
                    value={h.value}
                    onChange={(e) => handleHeaderChange(h.id, 'value', e.target.value)}
                    className="flex-1 text-sm border border-slate-200 rounded-lg px-3 py-2 font-mono focus:ring-primary-500 focus:border-primary-500"
                  />
                  <Button variant="ghost" size="sm" onClick={() => handleRemoveHeader(h.id)}>
                    <Trash2 size={16} className="text-slate-400 hover:text-rose-500" />
                  </Button>
                </div>
              ))}
              <Button variant="secondary" size="sm" onClick={handleAddHeader} icon={<Plus size={14} />}>
                Add Header
              </Button>
            </div>
          )}

          {activeTab === 'auth' && (
            <div className="max-w-md space-y-4">
              <div className="bg-blue-50 p-3 rounded-lg text-blue-700 text-sm flex gap-2">
                <AlertCircle size={16} className="mt-0.5 shrink-0" />
                <p>Using credentials from <strong>Settings</strong>. {settings.useMockMode ? '(Mock Mode Active)' : ''}</p>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-medium text-slate-500 mb-1">Username</label>
                  <input disabled value={settings.username} className="w-full bg-slate-100 border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-500" />
                </div>
                <div>
                  <label className="block text-xs font-medium text-slate-500 mb-1">Type</label>
                  <input disabled value="Basic Auth" className="w-full bg-slate-100 border border-slate-200 rounded-lg px-3 py-2 text-sm text-slate-500" />
                </div>
              </div>
            </div>
          )}

          {activeTab === 'body' && (
            <div className="relative">
              <textarea
                value={body}
                onChange={(e) => setBody(e.target.value)}
                className="w-full h-48 font-mono text-sm p-4 border border-slate-200 rounded-lg focus:ring-primary-500 focus:border-primary-500 bg-slate-900 text-slate-50 resize-y"
              />
              <div className="absolute top-2 right-2 flex gap-1">
                <button onClick={() => {
                  try {
                    setBody(JSON.stringify(JSON.parse(body), null, 2));
                  } catch (e) { /* ignore */ }
                }} className="text-xs bg-white/10 text-white hover:bg-white/20 px-2 py-1 rounded backdrop-blur-sm">
                  Prettify
                </button>
              </div>
            </div>
          )}

          {activeTab === 'params' && (
            <div className="text-center py-8 text-slate-400">
               <p>URL Parameters management coming soon. Edit URL directly above.</p>
            </div>
          )}
        </div>
      </div>

      {/* Response Panel */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 flex-1 flex flex-col min-h-[300px]">
        <div className="p-3 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
          <h3 className="font-semibold text-slate-700 flex items-center gap-2">
            <Terminal size={18} /> Response
          </h3>
          {response && (
            <div className="flex items-center gap-4 text-xs font-mono">
              <span className={`px-2 py-1 rounded ${response.status >= 200 && response.status < 300 ? 'bg-emerald-100 text-emerald-700' : 'bg-rose-100 text-rose-700'}`}>
                {response.status} {response.statusText}
              </span>
              <span className="text-slate-500">{response.time}ms</span>
              <span className="text-slate-500">{response.size}B</span>
            </div>
          )}
        </div>

        <div className="relative flex-1 bg-slate-900 overflow-auto group">
           {response ? (
             <>
                <button 
                  onClick={() => navigator.clipboard.writeText(JSON.stringify(response.data, null, 2))}
                  className="absolute top-4 right-4 p-2 bg-white/10 text-slate-300 rounded hover:bg-white/20 opacity-0 group-hover:opacity-100 transition-opacity"
                  title="Copy JSON"
                >
                  <Copy size={16} />
                </button>
               {response.error ? (
                 <div className="p-6 text-rose-400 font-mono">
                   Error: {response.message}
                   {settings.instanceUrl.includes('localhost') && (
                     <p className="mt-4 text-sm text-slate-400">
                       Note: Requesting localhost directly from a browser often fails due to CORS. 
                       Try Mock Mode in settings or use a browser extension to disable CORS.
                     </p>
                   )}
                 </div>
               ) : (
                 <pre className="language-json p-4 text-sm"><code className="language-json">{JSON.stringify(response.data, null, 2)}</code></pre>
               )}
             </>
           ) : (
             <div className="flex flex-col items-center justify-center h-full text-slate-600">
               <div className="w-16 h-16 bg-slate-800 rounded-full flex items-center justify-center mb-4">
                 <Play size={32} className="text-slate-500 ml-1" />
               </div>
               <p>Send a request to see the response here</p>
             </div>
           )}
        </div>

        {/* cURL Footer */}
        <div className="p-3 bg-slate-50 border-t border-slate-200 text-xs font-mono text-slate-500 truncate flex justify-between items-center">
          <div className="truncate flex-1 mr-4 opacity-75">
            {generateCurl()}
          </div>
          <button onClick={() => navigator.clipboard.writeText(generateCurl())} className="text-primary-600 hover:text-primary-700 font-medium whitespace-nowrap">
            Copy cURL
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Wifi, Plus, Trash2, Clock, Check, Copy, AlertTriangle } from 'lucide-react';
import { Button } from './ui/Button';
import { WebhookEvent } from '../types';
import { MOCK_WEBHOOK_PAYLOADS } from '../constants';

export const OutboundListener: React.FC = () => {
  const [isListening, setIsListening] = useState(false);
  const [events, setEvents] = useState<WebhookEvent[]>([]);
  const [selectedEventId, setSelectedEventId] = useState<string | null>(null);

  const toggleListening = () => {
    setIsListening(!isListening);
  };

  const simulateWebhook = () => {
    if (!isListening) return;

    const randomPayload = MOCK_WEBHOOK_PAYLOADS[Math.floor(Math.random() * MOCK_WEBHOOK_PAYLOADS.length)];
    const newEvent: WebhookEvent = {
      id: Date.now().toString(),
      timestamp: Date.now(),
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'User-Agent': 'ServiceNow/1.0',
        'X-ServiceNow-Source': 'Instance_123'
      },
      body: randomPayload,
      source: 'ServiceNow'
    };

    setEvents(prev => [newEvent, ...prev]);
    if (!selectedEventId) setSelectedEventId(newEvent.id);
  };

  const selectedEvent = events.find(e => e.id === selectedEventId);

  return (
    <div className="flex h-full gap-6">
      {/* Sidebar List */}
      <div className="w-80 flex flex-col bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        <div className="p-4 border-b border-slate-100 bg-slate-50/50">
          <div className="flex justify-between items-center mb-4">
            <h3 className="font-semibold text-slate-700">Webhook Listener</h3>
            <div className={`w-3 h-3 rounded-full ${isListening ? 'bg-emerald-500 animate-pulse' : 'bg-slate-300'}`}></div>
          </div>

          <div className="flex gap-2">
            <Button 
              variant={isListening ? 'danger' : 'primary'} 
              size="sm" 
              className="flex-1"
              onClick={toggleListening}
              icon={<Wifi size={14} />}
            >
              {isListening ? 'Stop' : 'Start Listening'}
            </Button>
            <Button 
              variant="secondary" 
              size="sm" 
              onClick={simulateWebhook}
              disabled={!isListening}
              title="Simulate an incoming webhook event"
            >
              Simulate
            </Button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-2 space-y-2">
          {events.length === 0 ? (
            <div className="text-center py-10 px-4 text-slate-400 text-sm">
              <Wifi size={32} className="mx-auto mb-3 opacity-20" />
              <p>No events received.</p>
              <p className="mt-2 text-xs">Click "Start Listening" then "Simulate" to test.</p>
            </div>
          ) : (
            events.map(event => (
              <button
                key={event.id}
                onClick={() => setSelectedEventId(event.id)}
                className={`w-full text-left p-3 rounded-xl transition-all border ${
                  selectedEventId === event.id 
                    ? 'bg-primary-50 border-primary-200 shadow-sm' 
                    : 'bg-white border-transparent hover:bg-slate-50'
                }`}
              >
                <div className="flex justify-between items-start mb-1">
                  <span className={`text-xs font-bold px-1.5 py-0.5 rounded ${
                    event.method === 'POST' ? 'bg-emerald-100 text-emerald-700' : 'bg-blue-100 text-blue-700'
                  }`}>
                    {event.method}
                  </span>
                  <span className="text-xs text-slate-400">
                    {new Date(event.timestamp).toLocaleTimeString()}
                  </span>
                </div>
                <div className="text-sm font-medium text-slate-700 truncate">
                  {event.body.short_description || event.body.event || 'Unknown Event'}
                </div>
              </button>
            ))
          )}
        </div>

        {events.length > 0 && (
          <div className="p-3 border-t border-slate-100">
            <Button variant="ghost" size="sm" className="w-full text-rose-500" onClick={() => {setEvents([]); setSelectedEventId(null);}}>
              Clear All
            </Button>
          </div>
        )}
      </div>

      {/* Detail View */}
      <div className="flex-1 bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden flex flex-col">
        {selectedEvent ? (
          <>
            <div className="p-6 border-b border-slate-100 bg-slate-50/30">
              <div className="flex justify-between items-start">
                <div>
                  <h2 className="text-xl font-bold text-slate-800 mb-1">Incoming Webhook Payload</h2>
                  <div className="flex items-center gap-4 text-sm text-slate-500">
                    <span className="flex items-center gap-1"><Clock size={14}/> {new Date(selectedEvent.timestamp).toLocaleString()}</span>
                    <span className="flex items-center gap-1 text-primary-600 font-medium">From: {selectedEvent.source}</span>
                  </div>
                </div>
                <Button variant="secondary" size="sm" icon={<Copy size={14}/>} onClick={() => navigator.clipboard.writeText(JSON.stringify(selectedEvent.body))}>
                  Copy JSON
                </Button>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-6">
              <div className="mb-6">
                <h4 className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-3">Headers</h4>
                <div className="bg-slate-50 rounded-lg border border-slate-200 p-3 text-sm font-mono text-slate-600">
                  {Object.entries(selectedEvent.headers).map(([k, v]) => (
                    <div key={k} className="flex gap-4 mb-1 last:mb-0">
